from sympy import factorint, nextprime
import math
def sopfr(n):
    if n <= 1:
        return 0
    return sum(p * e for p, e in factorint(n).items())
def is_sq(n):
    r = math.isqrt(n)
    return r * r == n
p = 2
while p < 10**6:
    if is_sq(sopfr(p-1)**2 + sopfr(p+1)**2):
        print(p)
    p = nextprime(p)

